#!/usr/bin/env Rscript
#
# Experiment 18: paper-facing scored-ordinal alpha simulation.
#
# The simulation uses three-category scored ordinal item responses generated by
# thresholding a latent Gaussian copula. Population alpha is computed from the
# exact scored-category covariance induced by the thresholds and latent
# correlations. It compares pairwise alpha with its overlap-subsample SE,
# saturated categorical EM, and a listwise sanity check.
#
# Outputs:
#   results/truth.csv
#   results/replicates.csv
#   results/summary.csv
#   results/metadata.csv

suppressPackageStartupMessages({
  library(misskappa)
})

usage <- function(status = 0L) {
  cat(paste0(
    "Usage: Rscript run_experiment.R [options]\n\n",
    "Options:\n",
    "  --help, -h          Show this help and exit.\n",
    "  --smoke             Cheap check: n=100, reps=4, core DGP/mechanism grid.\n",
    "  --reps N            Replicates per cell. Default: 40.\n",
    "  --n-grid CSV        Sample sizes. Default: 200,500.\n",
    "  --dgps CSV          DGPs. Default: all ordinal DGPs.\n",
    "  --mechanisms CSV    Missingness mechanisms. Default: mcar30,mar_anchor30.\n",
    "  --methods CSV       Methods. Default: pairwise,cat_em,listwise.\n",
    "  --seed-base N       Base seed. Default: 181800.\n",
    "  --out-dir PATH      Output directory. Default: script-local results/.\n",
    "  --progress          Print one line per design cell.\n\n",
    "Examples:\n",
    "  Rscript run_experiment.R --smoke --progress\n",
    "  Rscript run_experiment.R --reps 500 --n-grid 200,500,1000 --progress\n"
  ))
  quit(save = "no", status = status)
}

script_dir <- local({
  cmd <- commandArgs(FALSE)
  file_arg <- grep("^--file=", cmd, value = TRUE)
  if (length(file_arg) == 0L) getwd()
  else dirname(normalizePath(sub("^--file=", "", file_arg[[1L]]), mustWork = FALSE))
})

parse_csv_chr <- function(x) trimws(strsplit(x, ",", fixed = TRUE)[[1L]])
parse_csv_int <- function(x, arg) {
  out <- as.integer(strsplit(x, ",", fixed = TRUE)[[1L]])
  if (any(is.na(out))) stop(arg, " must be a comma-separated integer list.", call. = FALSE)
  unique(out)
}

parse_args <- function(argv) {
  opts <- list(
    smoke = FALSE,
    reps = 40L,
    n_grid = c(200L, 500L),
    dgps = c("ordinal_tau6", "ordinal_congeneric6", "ordinal_twofactor6"),
    mechanisms = c("mcar30", "mar_anchor30"),
    methods = c("pairwise", "cat_em", "listwise"),
    seed_base = 181800L,
    out_dir = file.path(script_dir, "results"),
    progress = FALSE
  )
  explicit <- list(reps = FALSE, n_grid = FALSE, dgps = FALSE,
                   mechanisms = FALSE, methods = FALSE)

  i <- 1L
  while (i <= length(argv)) {
    arg <- argv[[i]]
    if (arg %in% c("--help", "-h")) usage(0L)
    if (arg == "--smoke") {
      opts$smoke <- TRUE
      i <- i + 1L
      next
    }
    if (arg == "--progress") {
      opts$progress <- TRUE
      i <- i + 1L
      next
    }
    needs_value <- c("--reps", "--n-grid", "--dgps", "--mechanisms",
                     "--methods", "--seed-base", "--out-dir")
    if (arg %in% needs_value) {
      if (i == length(argv)) stop(arg, " needs a value.", call. = FALSE)
      val <- argv[[i + 1L]]
      if (arg == "--reps") {
        opts$reps <- as.integer(val); explicit$reps <- TRUE
      } else if (arg == "--n-grid") {
        opts$n_grid <- parse_csv_int(val, arg); explicit$n_grid <- TRUE
      } else if (arg == "--dgps") {
        opts$dgps <- parse_csv_chr(val); explicit$dgps <- TRUE
      } else if (arg == "--mechanisms") {
        opts$mechanisms <- parse_csv_chr(val); explicit$mechanisms <- TRUE
      } else if (arg == "--methods") {
        opts$methods <- parse_csv_chr(val); explicit$methods <- TRUE
      } else if (arg == "--seed-base") {
        opts$seed_base <- as.integer(val)
      } else if (arg == "--out-dir") {
        opts$out_dir <- val
      }
      i <- i + 2L
      next
    }
    stop("Unknown argument: ", arg, call. = FALSE)
  }

  if (opts$smoke) {
    if (!explicit$reps) opts$reps <- 4L
    if (!explicit$n_grid) opts$n_grid <- 100L
    if (!explicit$dgps) opts$dgps <- c("ordinal_tau6", "ordinal_congeneric6",
                                       "ordinal_twofactor6")
    if (!explicit$mechanisms) opts$mechanisms <- c("mcar30", "mar_anchor30")
    if (!explicit$methods) opts$methods <- c("pairwise", "cat_em", "listwise")
  }

  if (is.na(opts$reps) || opts$reps < 1L) stop("--reps must be >= 1.", call. = FALSE)
  if (any(is.na(opts$n_grid)) || any(opts$n_grid < 20L)) {
    stop("--n-grid entries must be integers >= 20.", call. = FALSE)
  }
  if (is.na(opts$seed_base)) stop("--seed-base must be an integer.", call. = FALSE)
  opts
}

opts <- parse_args(commandArgs(trailingOnly = TRUE))

scores <- 0:2
category_probs <- c(0.20, 0.50, 0.30)
thresholds <- stats::qnorm(cumsum(category_probs)[-length(category_probs)])
score_mean <- sum(category_probs * scores)
score_var <- sum(category_probs * (scores - score_mean)^2)

dgp_defs <- list(
  ordinal_tau6 = list(
    label = "Tau-equivalent ordinal, 6 items",
    short_label = "Tau-equivalent",
    family = "tau_equivalent",
    p = 6L,
    latent = function() {
      R <- matrix(0.55, 6L, 6L)
      diag(R) <- 1
      R
    }
  ),
  ordinal_congeneric6 = list(
    label = "Congeneric ordinal, 6 items",
    short_label = "Congeneric",
    family = "congeneric",
    p = 6L,
    latent = function() {
      lambda <- c(0.35, 0.45, 0.55, 0.65, 0.75, 0.85)
      R <- tcrossprod(lambda)
      diag(R) <- 1
      R
    }
  ),
  ordinal_twofactor6 = list(
    label = "Two-factor ordinal, 6 items",
    short_label = "Two-factor",
    family = "twofactor",
    p = 6L,
    latent = function() {
      R <- matrix(0.18, 6L, 6L)
      R[1:3, 1:3] <- 0.55
      R[4:6, 4:6] <- 0.55
      diag(R) <- 1
      R
    }
  )
)

valid_dgps <- names(dgp_defs)
valid_mechanisms <- c("complete", "mcar15", "mcar30", "mar_anchor15", "mar_anchor30")
valid_methods <- c("pairwise", "cat_em", "listwise")

if (!all(opts$dgps %in% valid_dgps)) {
  stop("--dgps must contain only: ", paste(valid_dgps, collapse = ","), call. = FALSE)
}
if (!all(opts$mechanisms %in% valid_mechanisms)) {
  stop("--mechanisms must contain only: ", paste(valid_mechanisms, collapse = ","), call. = FALSE)
}
if (!all(opts$methods %in% valid_methods)) {
  stop("--methods must contain only: ", paste(valid_methods, collapse = ","), call. = FALSE)
}
if (!exists("alpha", asNamespace("misskappa"), mode = "function")) {
  stop("misskappa::alpha() is not available; install the categorical alpha package build first.",
       call. = FALSE)
}

alpha_from_sigma <- function(Sigma) {
  p <- ncol(Sigma)
  (p / (p - 1)) * (1 - sum(diag(Sigma)) / sum(Sigma))
}

bvn_rect_prob <- function(xlo, xhi, ylo, yhi, rho) {
  if (abs(rho) < 1e-12) {
    return((stats::pnorm(xhi) - stats::pnorm(xlo)) *
             (stats::pnorm(yhi) - stats::pnorm(ylo)))
  }
  s <- sqrt(1 - rho * rho)
  integrand <- function(x) {
    stats::dnorm(x) *
      (stats::pnorm((yhi - rho * x) / s) -
         stats::pnorm((ylo - rho * x) / s))
  }
  stats::integrate(
    integrand, lower = xlo, upper = xhi, rel.tol = 1e-10,
    abs.tol = 1e-12, subdivisions = 200L
  )$value
}

ordinal_cov_cache <- new.env(parent = emptyenv())
ordinal_cov_from_latent <- function(rho) {
  key <- sprintf("%.12f", rho)
  if (exists(key, ordinal_cov_cache, inherits = FALSE)) {
    return(get(key, ordinal_cov_cache, inherits = FALSE))
  }
  lower <- c(-Inf, thresholds)
  upper <- c(thresholds, Inf)
  joint <- matrix(0, length(scores), length(scores))
  for (a in seq_along(scores)) {
    for (b in seq_along(scores)) {
      joint[a, b] <- bvn_rect_prob(lower[a], upper[a], lower[b], upper[b], rho)
    }
  }
  cov <- sum(outer(scores, scores) * joint) - score_mean^2
  assign(key, cov, ordinal_cov_cache)
  cov
}

sigma_for_dgp <- function(spec) {
  latent <- spec$latent()
  eig <- eigen(latent, symmetric = TRUE, only.values = TRUE)$values
  if (min(eig) <= 1e-8) stop("Latent correlation matrix is not positive definite.")
  p <- ncol(latent)
  Sigma <- matrix(0, p, p)
  diag(Sigma) <- score_var
  for (j in seq_len(p - 1L)) {
    for (k in (j + 1L):p) {
      Sigma[j, k] <- ordinal_cov_from_latent(latent[j, k])
      Sigma[k, j] <- Sigma[j, k]
    }
  }
  Sigma
}

simulate_complete <- function(n, spec) {
  latent <- spec$latent()
  z <- matrix(stats::rnorm(n * spec$p), n, spec$p) %*% chol(latent)
  x <- apply(z, 2L, function(col) findInterval(col, thresholds))
  x <- matrix(as.integer(x), nrow = n, ncol = spec$p)
  colnames(x) <- paste0("y", seq_len(spec$p))
  x
}

target_items <- function(p) seq.int(2L, p)

apply_mcar <- function(X, rate) {
  out <- X
  for (j in target_items(ncol(X))) {
    out[stats::runif(nrow(X)) < rate, j] <- NA_integer_
  }
  out
}

tune_intercept <- function(z, slope, rate, offset = 0.0) {
  f <- function(a) mean(stats::plogis(a + offset + slope * z)) - rate
  stats::uniroot(f, c(-12, 12))$root
}

apply_anchor_mar <- function(X, rate) {
  out <- X
  anchor_score <- scores[X[, 1L] + 1L]
  z <- as.numeric(scale(anchor_score))
  z[!is.finite(z)] <- 0
  slope <- -1.35
  for (j in target_items(ncol(X))) {
    shift <- (j - (ncol(X) + 2) / 2) * 0.08
    a <- tune_intercept(z, slope, rate, shift)
    p_miss <- stats::plogis(a + shift + slope * z)
    out[stats::runif(nrow(X)) < p_miss, j] <- NA_integer_
  }
  out
}

apply_missing <- function(X, mechanism) {
  if (mechanism == "complete") return(X)
  if (mechanism == "mcar15") return(apply_mcar(X, 0.15))
  if (mechanism == "mcar30") return(apply_mcar(X, 0.30))
  if (mechanism == "mar_anchor15") return(apply_anchor_mar(X, 0.15))
  if (mechanism == "mar_anchor30") return(apply_anchor_mar(X, 0.30))
  stop("Unknown mechanism: ", mechanism, call. = FALSE)
}

se_from_fit <- function(fit) {
  v <- as.numeric(stats::vcov(fit)[1L, 1L])
  if (!is.finite(v) || v < 0) return(NA_real_)
  sqrt(v)
}

fit_pairwise <- function(X) {
  fit <- misskappa::alpha(X, method = "available")
  list(estimate = as.numeric(stats::coef(fit)[["alpha"]]),
       se = se_from_fit(fit), iter = NA_integer_)
}

fit_cat_em <- function(X) {
  fit <- misskappa::alpha(
    X,
    method = "fiml",
    em_options = list(
      tol = 1e-7,
      max_iter = 20000L,
      prune_tol = 1e-10,
      start_alpha = 0.1,
      info_rcond = 1e-4
    )
  )
  list(estimate = as.numeric(stats::coef(fit)[["alpha"]]),
       se = se_from_fit(fit), iter = NA_integer_)
}

fit_listwise <- function(X) {
  cc <- stats::complete.cases(X)
  if (sum(cc) < ncol(X)) stop("too few complete rows for listwise alpha.")
  fit <- misskappa::alpha(X[cc, , drop = FALSE], method = "available")
  list(estimate = as.numeric(stats::coef(fit)[["alpha"]]),
       se = se_from_fit(fit), iter = NA_integer_)
}

fit_one <- function(X, method) {
  start <- proc.time()[["elapsed"]]
  out <- tryCatch({
    ans <- switch(
      method,
      pairwise = fit_pairwise(X),
      cat_em = fit_cat_em(X),
      listwise = fit_listwise(X)
    )
    ans$error <- ""
    ans
  }, error = function(e) {
    list(estimate = NA_real_, se = NA_real_, iter = NA_integer_,
         error = conditionMessage(e))
  })
  out$elapsed_ms <- 1000 * (proc.time()[["elapsed"]] - start)
  out
}

min_pair_count <- function(X) {
  p <- ncol(X)
  counts <- integer(p * (p - 1L) / 2L)
  idx <- 0L
  for (j in seq_len(p - 1L)) {
    for (k in (j + 1L):p) {
      idx <- idx + 1L
      counts[idx] <- sum(!is.na(X[, j]) & !is.na(X[, k]))
    }
  }
  min(counts)
}

row_seed <- function(cell, rep_id) opts$seed_base + 1000000L * cell + rep_id

truth_rows <- do.call(rbind, lapply(opts$dgps, function(name) {
  spec <- dgp_defs[[name]]
  latent <- spec$latent()
  Sigma <- sigma_for_dgp(spec)
  data.frame(
    dgp = name,
    dgp_label = spec$label,
    family = spec$family,
    p = ncol(Sigma),
    categories = length(scores),
    scores = paste(scores, collapse = ","),
    category_probs = paste(category_probs, collapse = ","),
    truth_alpha = alpha_from_sigma(Sigma),
    score_mean = score_mean,
    score_var = score_var,
    min_latent_cor = min(latent[upper.tri(latent)]),
    max_latent_cor = max(latent[upper.tri(latent)]),
    min_score_cov = min(Sigma[upper.tri(Sigma)]),
    max_score_cov = max(Sigma[upper.tri(Sigma)]),
    truth_method = "exact scored covariance from ordinal Gaussian copula",
    stringsAsFactors = FALSE
  )
}))

truth_for <- function(dgp) truth_rows$truth_alpha[match(dgp, truth_rows$dgp)]

split_keys <- function(data, keys) interaction(data[, keys], drop = TRUE, lex.order = TRUE)

summarize_replicates <- function(df) {
  keys <- c("dgp", "dgp_label", "family", "p", "mechanism", "n", "method")
  out <- lapply(split(df, split_keys(df, keys)), function(g) {
    ok <- is.finite(g$estimate)
    se_ok <- ok & is.finite(g$se) & g$se > 0
    z <- (g$estimate[se_ok] - g$truth[se_ok]) / g$se[se_ok]
    cov95 <- abs(g$estimate[se_ok] - g$truth[se_ok]) <= stats::qnorm(0.975) * g$se[se_ok]
    data.frame(
      dgp = g$dgp[[1L]],
      dgp_label = g$dgp_label[[1L]],
      family = g$family[[1L]],
      p = g$p[[1L]],
      mechanism = g$mechanism[[1L]],
      n = g$n[[1L]],
      method = g$method[[1L]],
      reps = length(unique(g$rep)),
      n_valid = sum(ok),
      failures = sum(!ok),
      truth = g$truth[[1L]],
      mean_estimate = if (any(ok)) mean(g$estimate[ok]) else NA_real_,
      bias = if (any(ok)) mean(g$estimate[ok] - g$truth[ok]) else NA_real_,
      sd_estimate = if (sum(ok) > 1L) stats::sd(g$estimate[ok]) else NA_real_,
      mc_se_bias = if (sum(ok) > 1L) stats::sd(g$estimate[ok]) / sqrt(sum(ok)) else NA_real_,
      rmse = if (any(ok)) sqrt(mean((g$estimate[ok] - g$truth[ok])^2)) else NA_real_,
      mse = if (any(ok)) mean((g$estimate[ok] - g$truth[ok])^2) else NA_real_,
      mean_se = if (any(se_ok)) mean(g$se[se_ok]) else NA_real_,
      se_over_sd = if (sum(se_ok) > 1L && stats::sd(g$estimate[se_ok]) > 1e-12) {
        mean(g$se[se_ok]) / stats::sd(g$estimate[se_ok])
      } else NA_real_,
      coverage95 = if (any(se_ok)) mean(cov95) else NA_real_,
      mean_z = if (length(z)) mean(z) else NA_real_,
      sd_z = if (length(z) > 1L) stats::sd(z) else NA_real_,
      mean_ci_length = if (any(se_ok)) mean(2 * stats::qnorm(0.975) * g$se[se_ok]) else NA_real_,
      mean_elapsed_ms = mean(g$elapsed_ms, na.rm = TRUE),
      median_elapsed_ms = stats::median(g$elapsed_ms, na.rm = TRUE),
      mean_observed_fraction = mean(g$observed_fraction, na.rm = TRUE),
      mean_complete_rows = mean(g$complete_rows, na.rm = TRUE),
      min_pair_count_min = min(g$min_pair_count, na.rm = TRUE),
      mean_em_iter = mean(g$em_iter, na.rm = TRUE),
      stringsAsFactors = FALSE
    )
  })
  ans <- do.call(rbind, out)
  ans <- ans[order(ans$dgp, ans$mechanism, ans$n, ans$method), ]
  rownames(ans) <- NULL
  ans
}

log_progress <- function(...) {
  if (opts$progress) message(format(Sys.time(), "%H:%M:%S"), " ", sprintf(...))
}

grid <- expand.grid(
  dgp = opts$dgps,
  mechanism = opts$mechanisms,
  n = opts$n_grid,
  stringsAsFactors = FALSE
)
grid <- grid[order(grid$dgp, grid$mechanism, grid$n), , drop = FALSE]

rep_rows <- list()
t0 <- Sys.time()
for (cell in seq_len(nrow(grid))) {
  dgp_name <- grid$dgp[cell]
  spec <- dgp_defs[[dgp_name]]
  truth <- truth_for(dgp_name)
  log_progress(
    "cell %d/%d: %s %s n=%d reps=%d",
    cell, nrow(grid), dgp_name, grid$mechanism[cell],
    grid$n[cell], opts$reps
  )
  for (rep_id in seq_len(opts$reps)) {
    set.seed(row_seed(cell, rep_id))
    X_star <- simulate_complete(grid$n[cell], spec)
    X <- apply_missing(X_star, grid$mechanism[cell])
    observed_fraction <- mean(!is.na(X))
    complete_rows <- sum(stats::complete.cases(X))
    min_pair <- min_pair_count(X)
    for (method in opts$methods) {
      fit <- fit_one(X, method)
      rep_rows[[length(rep_rows) + 1L]] <- data.frame(
        dgp = dgp_name,
        dgp_label = spec$label,
        family = spec$family,
        p = spec$p,
        categories = length(scores),
        mechanism = grid$mechanism[cell],
        n = grid$n[cell],
        rep = rep_id,
        seed = row_seed(cell, rep_id),
        method = method,
        truth = truth,
        estimate = fit$estimate,
        bias = fit$estimate - truth,
        se = fit$se,
        elapsed_ms = fit$elapsed_ms,
        em_iter = fit$iter,
        observed_fraction = observed_fraction,
        complete_rows = complete_rows,
        min_pair_count = min_pair,
        error = fit$error,
        stringsAsFactors = FALSE
      )
    }
  }
}

replicates <- if (length(rep_rows)) do.call(rbind, rep_rows) else data.frame()
summary <- summarize_replicates(replicates)

dir.create(opts$out_dir, recursive = TRUE, showWarnings = FALSE)
write.csv(truth_rows, file.path(opts$out_dir, "truth.csv"), row.names = FALSE)
write.csv(replicates, file.path(opts$out_dir, "replicates.csv"), row.names = FALSE)
write.csv(summary, file.path(opts$out_dir, "summary.csv"), row.names = FALSE)

metadata <- data.frame(
  key = c(
    "generated_at", "script", "smoke", "reps", "n_grid", "dgps",
    "mechanisms", "methods", "seed_base", "elapsed_seconds",
    "categories", "scores", "category_probs", "dgp_class",
    "misskappa_version", "r_version", "pairwise_se_status"
  ),
  value = c(
    format(Sys.time(), "%Y-%m-%d %H:%M:%S %z"),
    normalizePath(file.path(script_dir, "run_experiment.R"), mustWork = FALSE),
    as.character(opts$smoke),
    as.character(opts$reps),
    paste(opts$n_grid, collapse = ","),
    paste(opts$dgps, collapse = ","),
    paste(opts$mechanisms, collapse = ","),
    paste(opts$methods, collapse = ","),
    as.character(opts$seed_base),
    as.character(round(as.numeric(difftime(Sys.time(), t0, units = "secs")), 3)),
    as.character(length(scores)),
    paste(scores, collapse = ","),
    paste(category_probs, collapse = ","),
    "three-category scored ordinal Gaussian-copula threshold model",
    as.character(utils::packageVersion("misskappa")),
    R.version.string,
    "available through misskappa::alpha(method = 'available')"
  ),
  stringsAsFactors = FALSE
)
write.csv(metadata, file.path(opts$out_dir, "metadata.csv"), row.names = FALSE)

cat("Wrote:\n")
cat("  ", normalizePath(file.path(opts$out_dir, "truth.csv"), mustWork = FALSE), "\n", sep = "")
cat("  ", normalizePath(file.path(opts$out_dir, "replicates.csv"), mustWork = FALSE), "\n", sep = "")
cat("  ", normalizePath(file.path(opts$out_dir, "summary.csv"), mustWork = FALSE), "\n", sep = "")
cat("  ", normalizePath(file.path(opts$out_dir, "metadata.csv"), mustWork = FALSE), "\n", sep = "")
